        this.synthesizer.channelSetMute(channel, mute)
    }
    
    /**
     * Resets the mute/solo state of all channels
     */
    public override fun resetChannelStates(): Unit{
        this.synthesizer.resetChannelStates()
    }
    
    /**
     * Gets the solo state of a channel.
     */
    public override fun setChannelSolo(channel: Double, solo: Boolean): Unit{
        this.synthesizer.channelSetSolo(channel, solo)
    }
    
    /**
     * Gets or sets the current and initial volume of the given channel.
     */
    public override fun setChannelVolume(channel: Double, volume: Double): Unit{
        var paramvolume = volume
        paramvolume = com.omnifret.gplayer.core.ecmaScript.Math.max(paramvolume, com.omnifret.gplayer.synth.SynthConstants.MinVolume)
        this.synthesizer.channelSetMixVolume(channel, paramvolume)
    }
    
    /**
     */
    private fun _onSamplesPlayed(sampleCount: Double): Unit{
        if (sampleCount == 0.0)
        {
            return
        }
        var playedMillis: Double = (sampleCount / this.synthesizer.outSampleRate) * (1000.0).toDouble()
        this._notPlayedSamples -= sampleCount * com.omnifret.gplayer.synth.SynthConstants.AudioChannels
        this.updateTimePosition(this._timePosition + playedMillis, false)
        this.checkForFinish()
    }
    
    protected fun checkForFinish(): Unit{
        var startTick: Double = 0.0
        var endTick: Double = 0.0
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.playbackRange)) && this.sequencer.isPlayingMain))
        {
            startTick = this.playbackRange!!.startTick
            endTick = this.playbackRange!!.endTick
        }
        else 
        {
            endTick = this.sequencer.currentEndTick
        }
        if (this._tickPosition >= endTick)
        {
            if (this._notPlayedSamples <= 0)
            {
                this._notPlayedSamples = 0.0
                if (this.sequencer.isPlayingCountIn)
                {
                    com.omnifret.gplayer.Logger.debug("GPlayerSynth", "Finished playback (count-in)")
                    this.sequencer.resetCountIn()
                    this.timePosition = this.sequencer.currentTime
                    this._playInternal()
                    this.output.resetSamples()
                }
                else if (this.sequencer.isPlayingOneTimeMidi)
                {
                    com.omnifret.gplayer.Logger.debug("GPlayerSynth", "Finished playback (one time)")
                    this.output.resetSamples()
                    this.state = com.omnifret.gplayer.synth.PlayerState.Paused
                    this._stopOneTimeMidi()
                }
                else if (this.isLooping)
                {
                    com.omnifret.gplayer.Logger.debug("GPlayerSynth", "Finished playback (main looping)")
                    ((this.finished as com.omnifret.gplayer.EventEmitter)).trigger()
                    this.tickPosition = startTick
                    this._synthStopping = false
                }
                else if (this.synthesizer.activeVoiceCount > 0)
                {
                    if (!this._synthStopping)
                    {
                        com.omnifret.gplayer.Logger.debug("GPlayerSynth", "Signaling synth to stop all voices (all samples played)")
                        this.synthesizer.noteOffAll(true)
                        this._synthStopping = true
                    }
                }
                else 
                {
                    this._synthStopping = false
                    com.omnifret.gplayer.Logger.debug("GPlayerSynth", "Finished playback (main)")
                    ((this.finished as com.omnifret.gplayer.EventEmitter)).trigger()
                    this.stop()
                }
            }
            else 
            {
                if (!this._synthStopping)
                {
                    com.omnifret.gplayer.Logger.debug("GPlayerSynth", "Signaling synth to stop all voices (not all samples played)")
                    this.synthesizer.noteOffAll(true)
                    this._synthStopping = true
                }
            }
        }
    }
    
    private fun _stopOneTimeMidi(): Unit{
        this.output.pause()
        this.synthesizer.noteOffAll(true)
        this.sequencer.resetOneTimeMidi()
        this.timePosition = this.sequencer.currentTime
    }
    
    /**
     */
    private fun _createPositionChangedEventArgs(isSeek: Boolean): com.omnifret.gplayer.synth.PositionChangedEventArgs{
        var currentTime: Double = this._timePosition
        var currentTick: Double = this.sequencer.currentTimePositionToTickPosition(currentTime)
        var endTime: Double = this.sequencer.currentEndTime
        var endTick: Double = this.sequencer.currentEndTick
        if (currentTime > endTime)
        {
            currentTime = endTime
            currentTick = endTick
        }
        return com.omnifret.gplayer.synth.PositionChangedEventArgs(currentTime, 
        endTime, 
        currentTick, 
        endTick, 
        isSeek, 
        this.sequencer.currentTempo, 
        this.sequencer.modifiedTempo)
    }
    
    /**
     */
    protected open fun updateTimePosition(timePosition: Double, isSeek: Boolean): Unit{
        this._timePosition = timePosition
        var args: com.omnifret.gplayer.synth.PositionChangedEventArgs = this._createPositionChangedEventArgs(isSeek)
        this._tickPosition = args.currentTick
        var mode: String = if(this.sequencer.isPlayingMain)  "main" else if(this.sequencer.isPlayingCountIn)  "count-in" else "one-time"
        com.omnifret.gplayer.Logger.debug("GPlayerSynth", """Position changed: (time: ${(args.currentTime).toTemplate()}/${(args.endTime).toTemplate()}, tick: ${(args.currentTick).toTemplate()}/${(args.endTick).toTemplate()}, Active Voices: ${(this.synthesizer.activeVoiceCount).toTemplate()} (${(mode).toTemplate()}), Tempo original: ${(this.sequencer.currentTempo).toTemplate()}, Tempo modified: ${(this.sequencer.modifiedTempo).toTemplate()})""")
        if (this.sequencer.isPlayingMain)
        {
            this._currentPosition = args
            ((this.positionChanged as com.omnifret.gplayer.EventEmitterOfT<com.omnifret.gplayer.synth.PositionChangedEventArgs>)).trigger(args)
        }
        if (isSeek)
        {
            this.playedEventsQueue.clear()
        }
        else 
        {
            var playedEvents: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.midi.MidiEvent> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.midi.MidiEvent>(
            )
            
            while (!this.playedEventsQueue.isEmpty && this.playedEventsQueue.peek()!!.time < args.currentTime)
            {
                var synthEvent: com.omnifret.gplayer.synth.synthesis.SynthEvent = this.playedEventsQueue.dequeue()!!
                playedEvents.push(synthEvent.event)
            }
            if (playedEvents.length > 0)
            {
                playedEvents.reverse()
                ((this.midiEventsPlayed as com.omnifret.gplayer.EventEmitterOfT<com.omnifret.gplayer.synth.MidiEventsPlayedEventArgs>)).trigger(com.omnifret.gplayer.synth.MidiEventsPlayedEventArgs(playedEvents))
            }
        }
    }
    
    /**
     * This event is fired when the player is ready to be interacted with.
     */
    public override lateinit var ready: com.omnifret.gplayer.IEventEmitter
    
    /**
     * This event is fired when all required data for playback is loaded and ready.
     */
    public override var readyForPlayback: com.omnifret.gplayer.IEventEmitter = com.omnifret.gplayer.EventEmitter()
    
    
    /**
     * This event is fired when the playback of the whole song finished.
     */
    public override var finished: com.omnifret.gplayer.IEventEmitter = com.omnifret.gplayer.EventEmitter()
    
    
    /**
     * This event is fired when the SoundFont needed for playback was loaded.
     */
    public override var soundFontLoaded: com.omnifret.gplayer.IEventEmitter = com.omnifret.gplayer.EventEmitter()
    
    
    /**
     * This event is fired when the loading of the SoundFont failed.
     */
    public override var soundFontLoadFailed: com.omnifret.gplayer.IEventEmitterOfT<kotlin.Throwable> = com.omnifret.gplayer.EventEmitterOfT<kotlin.Throwable>()
    
    
    /**
     * This event is fired when the Midi file needed for playback was loaded.
     */
    public override lateinit var midiLoaded: com.omnifret.gplayer.IEventEmitterOfT<com.omnifret.gplayer.synth.PositionChangedEventArgs>
    
    /**
     * This event is fired when the loading of the Midi file failed.
     */
    public override var midiLoadFailed: com.omnifret.gplayer.IEventEmitterOfT<kotlin.Throwable> = com.omnifret.gplayer.EventEmitterOfT<kotlin.Throwable>()
    
    
    /**
     * This event is fired when the playback state changed.
     */
    public override lateinit var stateChanged: com.omnifret.gplayer.IEventEmitterOfT<com.omnifret.gplayer.synth.PlayerStateChangedEventArgs>
    
    /**
     * This event is fired when the current playback position of/ the song changed.
     */
    public override lateinit var positionChanged: com.omnifret.gplayer.IEventEmitterOfT<com.omnifret.gplayer.synth.PositionChangedEventArgs>
    
    /**
     * The event is fired when certain midi events were sent to the audio output device for playback.
     */
    public override var midiEventsPlayed: com.omnifret.gplayer.IEventEmitterOfT<com.omnifret.gplayer.synth.MidiEventsPlayedEventArgs> = com.omnifret.gplayer.EventEmitterOfT<com.omnifret.gplayer.synth.MidiEventsPlayedEventArgs>()
    
    
    /**
     * The event is fired when the playback range within the player was updated.
     */
    public override lateinit var playbackRangeChanged: com.omnifret.gplayer.IEventEmitterOfT<com.omnifret.gplayer.synth.PlaybackRangeChangedEventArgs>
    
    /**
     */
    internal fun hasSamplesForProgram(program: Double): Boolean{
        return this.synthesizer.hasSamplesForProgram(program)
    }
    
    /**
     */
    internal fun hasSamplesForPercussion(key: Double): Boolean{
        return this.synthesizer.hasSamplesForPercussion(key)
    }
    
    /**
     * Loads the synchronization information from the given score (used for backing tracks and external media).
     */
    public override fun loadBackingTrack(_score: com.omnifret.gplayer.model.Score): Unit{
    }
    
    /**
     * Updates the points used to synchronize the backing track with the synthesized audio for correct cursor placement.
     */
    public override fun updateSyncPoints(_syncPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.BackingTrackSyncPoint>): Unit{
    }
    
}

/**
 * An audio exporter allowing streaming synthesis of audio samples with a fixed configuration.
 * This is the internal synchronous version of the public .
 */
@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
public interface IGPlayerSynthAudioExporter
{
    /**
     * Renders the next chunk of audio and provides it as result.
     * @param milliseconds The rough number of milliseconds that should be synthesized and exported as chunk.
     */
    fun render(milliseconds: Double): com.omnifret.gplayer.synth.AudioExportChunk?
    
}

/**
 * A audio exporter allowing streaming synthesis of audio samples with a fixed configuration.
 */
@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
public class SynthAudioExporter: com.omnifret.gplayer.synth.IGPlayerSynthAudioExporter
{
    private var _synth: com.omnifret.gplayer.synth.synthesis.TinySoundFont
    
    private var _sequencer: com.omnifret.gplayer.synth.MidiFileSequencer
    
    public constructor(options: com.omnifret.gplayer.synth.AudioExportOptions){
        this._synth = com.omnifret.gplayer.synth.synthesis.TinySoundFont(options.sampleRate)
        this._sequencer = com.omnifret.gplayer.synth.MidiFileSequencer(this._synth)
        this._synth.masterVolume = com.omnifret.gplayer.core.ecmaScript.Math.max(options.masterVolume, com.omnifret.gplayer.synth.SynthConstants.MinVolume)
        this._synth.metronomeVolume = com.omnifret.gplayer.core.ecmaScript.Math.max(options.metronomeVolume, com.omnifret.gplayer.synth.SynthConstants.MinVolume)
    }
    
    /**
     * Loads the specified sound font.
     * @param `data` The soundfont data.
     */
    public fun loadSoundFont(`data`: com.omnifret.gplayer.core.ecmaScript.Uint8Array): Unit{
        var input: com.omnifret.gplayer.io.ByteBuffer = com.omnifret.gplayer.io.ByteBuffer.fromBuffer(`data`)
        var soundFont: com.omnifret.gplayer.synth.soundfont.Hydra = com.omnifret.gplayer.synth.soundfont.Hydra()
        soundFont.load(input)
        var programs: com.omnifret.gplayer.core.ecmaScript.Set<Double> = this._sequencer.instrumentPrograms
        var percussionKeys: com.omnifret.gplayer.core.ecmaScript.Set<Double> = this._sequencer.percussionKeys
        this._synth.loadPresets(soundFont, programs, percussionKeys, true)
    }
    
    /**
     * Loads the specified presets.
     * @param presets The presets to use.
     */
    internal fun loadPresets(presets: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.synthesis.Preset>?): Unit{
        this._synth.presets = presets
    }
    
    /**
     * Limits the time range for which the export is done.
     * @param range The time range
     */
    public fun limitExport(range: com.omnifret.gplayer.synth.PlaybackRange): Unit{
        this._sequencer.mainPlaybackRange = range
        this._sequencer.mainSeek(this._sequencer.mainTickPositionToTimePosition(range.startTick))
    }
    
    /**
     * Sets the transposition pitch of a given channel. This pitch is additionally applied beside the
     * ones applied already via .
     * @param channel The channel number
     * @param semitones The number of semitones to apply as pitch offset.
     */
    public fun setChannelTranspositionPitch(channel: Double, semitones: Double): Unit{
        this._synth.setChannelTranspositionPitch(channel, semitones)
    }
    
    /**
     * Applies the given transposition pitches used for general pitch changes that should be applied to the song.
     * Used for general transpositions applied to the file.
     */
    public fun applyTranspositionPitches(mainTranspositionPitches: com.omnifret.gplayer.collections.DoubleDoubleMap): Unit{
        this._synth.applyTranspositionPitches(mainTranspositionPitches)
    }
    
    /**
     * Loads the given midi file for synthesis.
     * @param midi The midi file.
     */
    public fun loadMidiFile(midi: com.omnifret.gplayer.midi.MidiFile): Unit{
        this._sequencer.loadMidi(midi)
    }
    
    /**
     * Updates the sync points used for time synchronization with a backing track.
     * @param syncPoints The sync points.
     */
    public fun updateSyncPoints(syncPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.BackingTrackSyncPoint>): Unit{
        this._sequencer.mainUpdateSyncPoints(syncPoints)
    }
    
    /**
     * Sets the current and initial volume of the given channel.
     * @param channel The channel number.
     * @param volume The volume of of the channel (0.0-1.0)
     */
    public fun channelSetMixVolume(channel: Double, volume: Double): Unit{
        var paramvolume = volume
        paramvolume = com.omnifret.gplayer.core.ecmaScript.Math.max(paramvolume, com.omnifret.gplayer.synth.SynthConstants.MinVolume)
        this._synth.channelSetMixVolume(channel, paramvolume)
    }
    
    private var _generatedAudioCurrentTime: Double = 0.0
    
    private var _generatedAudioEndTime: Double = 0.0
    
    public fun setup(): Unit{
        this._synth.setupMetronomeChannel(this._sequencer.metronomeChannel, this._synth.metronomeVolume)
        var syncPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.BackingTrackSyncPoint> = this._sequencer.currentSyncPoints
        var endTime: Double = this._sequencer.currentEndTime
        if (syncPoints.length == 0.0)
        {
            this._generatedAudioEndTime = endTime
        }
        else 
        {
            var lastSyncPoint: com.omnifret.gplayer.synth.BackingTrackSyncPoint = syncPoints[(syncPoints.length - (1.0).toDouble()).toInt()]
            var endTime: Double = lastSyncPoint.syncTime
            var remainingTicks: Double = this._sequencer.currentEndTick - lastSyncPoint.synthTick
            if (remainingTicks > 0)
            {
                endTime += com.omnifret.gplayer.midi.MidiUtils.ticksToMillis(remainingTicks, lastSyncPoint.syncBpm)
            }
            this._generatedAudioEndTime = endTime
        }
    }
    
    /**
     * Renders the next chunk of audio and provides it as result.
     */
    public override fun render(milliseconds: Double): com.omnifret.gplayer.synth.AudioExportChunk?{
        if (this._sequencer.isFinished)
        {
            return null
        }
        var oneMicroBufferMillis: Double = (com.omnifret.gplayer.synth.SynthConstants.MicroBufferSize * (1000.0).toDouble()) / this._synth.outSampleRate
        var microBufferCount: Double = com.omnifret.gplayer.core.ecmaScript.Math.ceil(milliseconds / oneMicroBufferMillis)
        var samples: com.omnifret.gplayer.core.ecmaScript.Float32Array = com.omnifret.gplayer.core.ecmaScript.Float32Array(com.omnifret.gplayer.synth.SynthConstants.MicroBufferSize * microBufferCount * com.omnifret.gplayer.synth.SynthConstants.AudioChannels)
        var syncPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.synth.BackingTrackSyncPoint> = this._sequencer.currentSyncPoints
        var bufferPos: Double = 0.0
        var subBufferTime: Double = this._generatedAudioCurrentTime
        if (true) {
            var i: Double = 0.0
            
            while(i < microBufferCount){
                if (syncPoints.length > 0)
                {
                    this._sequencer.currentUpdateSyncPoints(subBufferTime)
                    this._sequencer.currentUpdateCurrentTempo(this._sequencer.currentTime)
                    var newSpeed: Double = this._sequencer.syncPointTempo / this._sequencer.currentTempo
                    if (this._sequencer.playbackSpeed != newSpeed)
                    {
                        this._sequencer.playbackSpeed = newSpeed
                    }
                }
                this._sequencer.fillMidiEventQueue()
                this._synth.synthesize(samples, bufferPos, com.omnifret.gplayer.synth.SynthConstants.MicroBufferSize)
                bufferPos += com.omnifret.gplayer.synth.SynthConstants.MicroBufferSize * com.omnifret.gplayer.synth.SynthConstants.AudioChannels
                subBufferTime += oneMicroBufferMillis
                if (this._sequencer.isFinished)
                {
                    break
                }
                i++
            }
        }
        if (bufferPos < samples.length)
        {
            samples = samples.subarray(0.0, bufferPos)
        }
        var chunk: com.omnifret.gplayer.synth.AudioExportChunk = com.omnifret.gplayer.synth.AudioExportChunk()
        chunk.currentTime = this._generatedAudioCurrentTime
        chunk.endTime = this._generatedAudioEndTime
        chunk.currentTick = this._sequencer.currentTimePositionToTickPosition(this._sequencer.currentTime)
        chunk.endTick = this._sequencer.currentEndTick
        this._generatedAudioCurrentTime += milliseconds
        chunk.samples = samples
        if (this._sequencer.isFinished)
        {
            this._synth.noteOffAll(true)
        }
        return chunk
    }
    
}

